import { describe, expect, it } from '@a0n/gnosis/test';
import {
  CACHE_OBSERVATION_LEAN_MODULE,
  classifyEscCacheLookup,
  marginalFoldWork,
  positiveFoldWork,
  resolveQuery,
  totalMarginalFoldWork,
  wasmEscObservation,
} from './cache-observation';
import type { EscWasmSegmentRecord } from './edge-side-compute';

describe('cache-observation (Lean CacheObservation mirror)', () => {
  it('marginalFoldWork matches Lean marginal_fold_work', () => {
    const w = positiveFoldWork(3);
    expect(marginalFoldWork({ kind: 'hit' })).toBe(0);
    expect(marginalFoldWork({ kind: 'cold_miss', w })).toBe(3);
    expect(marginalFoldWork({ kind: 'stale_miss', w })).toBe(3);
  });

  it('resolveQuery matches Lean tag semantics', () => {
    const w = positiveFoldWork(1);
    expect(resolveQuery({ occupied: true, keyMatches: true, entryValid: true }, w)).toEqual({
      kind: 'hit',
    });
    expect(resolveQuery({ occupied: true, keyMatches: true, entryValid: false }, w)).toEqual({
      kind: 'stale_miss',
      w,
    });
    expect(resolveQuery({ occupied: false, keyMatches: false, entryValid: false }, w)).toEqual({
      kind: 'cold_miss',
      w,
    });
  });

  it('totalMarginalFoldWork matches cold then hits amortization shape', () => {
    const w = positiveFoldWork(2);
    const qs = [
      { kind: 'cold_miss' as const, w },
      { kind: 'hit' as const },
      { kind: 'hit' as const },
    ];
    expect(totalMarginalFoldWork(qs)).toBe(2);
  });

  it('classifyEscCacheLookup bridges ESC lookup to resolution', () => {
    const w = positiveFoldWork(1);
    const rec: EscWasmSegmentRecord = {
      version: 1,
      artifactId: 'a',
      exportName: 'm',
      abi: 'j',
      payload: 1,
      logs: '',
    };
    expect(
      classifyEscCacheLookup({
        cached: rec,
        signatureMatches: true,
        entryValid: true,
        w,
      })
    ).toEqual({ kind: 'hit' });
    expect(
      classifyEscCacheLookup({
        cached: rec,
        signatureMatches: true,
        entryValid: false,
        w,
      })
    ).toEqual({ kind: 'stale_miss', w });
    expect(
      classifyEscCacheLookup({
        cached: null,
        signatureMatches: false,
        w,
      })
    ).toEqual({ kind: 'cold_miss', w });
  });

  it('wasmEscObservation carries formal ref and consistent marginal', () => {
    const obs = wasmEscObservation({ kind: 'hit' });
    expect(obs.formalRef).toBe(CACHE_OBSERVATION_LEAN_MODULE);
    expect(obs.marginalFoldWork).toBe(0);
    expect(obs.resolution.kind).toBe('hit');
  });

  it('positiveFoldWork rejects non-positive', () => {
    expect(() => positiveFoldWork(0)).toThrow(RangeError);
    expect(() => positiveFoldWork(1.5)).toThrow(RangeError);
  });
});
